function solve(landStartTime: number[], landDuration: number[], waterStartTime: number[], waterDuration: number[]): number {
    // Calculate all possible end times for land and water attractions
    const landEndTimes: number[] = [];
    for (let i = 0; i < landStartTime.length; ++i) {
        landEndTimes.push(landStartTime[i] + landDuration[i]);
    }

    const waterEndTimes: number[] = [];
    for (let j = 0; j < waterStartTime.length; ++j) {
        waterEndTimes.push(waterStartTime[j] + waterDuration[j]);
    }

    // Find the minimum end time for each attraction
    const minLandEnd = Math.min(...landEndTimes);
    const minWaterEnd = Math.min(...waterEndTimes);

    // Calculate the earliest possible time when both attractions are completed
    // Case 1: Land first, then water
    const landFirst = Math.max(minLandEnd, waterStartTime[0]) + waterDuration[0];

    // Case 2: Water first, then land
    const waterFirst = Math.max(minWaterEnd, landStartTime[0]) + landDuration[0];

    // Return the minimum of the two cases
    return Math.min(landFirst, waterFirst);
}
